UPDATE notification_templates SET content = '<div style="font-family: ''Microsoft YaHei'', Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px;">\n  <div style="background: linear-gradient(135deg, #a18cd1 0%, #fbc2eb 100%); color: white; padding: 30px; border-radius: 10px 10px 0 0; text-align: center;">\n    <h1 style="margin: 0; font-size: 24px;">📋 任务通知</h1>\n  </div>\n  <div style="background: #f8f9fa; padding: 30px; border: 1px solid #e9ecef; border-top: none; border-radius: 0 0 10px 10px;">\n    <p><strong>任务：</strong>${taskTitle}</p>\n    <p><strong>状态：</strong>${status}</p>\n    <p>${content}</p>\n    <hr style="border: none; border-top: 1px solid #e9ecef; margin: 20px 0;">\n    <p style="color: #666; font-size: 14px;">⏰ ${time}</p>\n    <div style="text-align: center; margin-top: 20px;">\n      <a href="${domain}/scheduler" style="display: inline-block; background: #a18cd1; color: white; padding: 12px 24px; text-decoration: none; border-radius: 5px;">查看任务</a>\n    </div>\n  </div>\n</div>' WHERE template_code = 'TASK_EMAIL';
UPDATE notification_templates SET content = '<div style="font-family:''Microsoft YaHei'',Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px;"><div style="background:linear-gradient(135deg,#ff6b6b 0%,#ee5a24 100%);color:white;padding:20px;border-radius:10px 10px 0 0;text-align:center;"><h1 style="margin:0;font-size:24px;">⚠️ Token 耗尽警告</h1></div><div style="background:#f8f9fa;padding:20px;border:1px solid #e9ecef;border-top:none;border-radius:0 0 10px 10px;"><p>API Token 配额不足，请及时补充。</p><p style="color:#666;margin-top:20px;">时间：${time}</p><p style="margin-top:15px;"><a href="${domain}/tokens" style="display:inline-block;background:#ff6b6b;color:white;padding:10px 20px;text-decoration:none;border-radius:5px;">管理Token</a></p></div></div>' WHERE template_code = 'TOKEN_EXHAUSTED_EMAIL';
UPDATE notification_templates SET content = '<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px;">\n  <div style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: white; padding: 30px; border-radius: 10px 10px 0 0; text-align: center;">\n    <h1 style="margin: 0; font-size: 24px;">📧 邮箱验证码</h1>\n  </div>\n  <div style="background: #f8f9fa; padding: 30px; border: 1px solid #e9ecef; border-top: none; border-radius: 0 0 10px 10px;">\n    <p>您好，</p>\n    <p>您的邮箱验证码是：</p>\n    <div style="text-align: center; margin: 30px 0;">\n      <span style="font-size: 32px; font-weight: bold; color: #667eea; letter-spacing: 5px;">${code}</span>\n    </div>\n    <p>验证码有效期为 ${expireMinutes} 分钟，请尽快使用。</p>\n    <p style="color: #dc3545; font-size: 14px;">⚠️ 如果这不是您的操作，请忽略此邮件。</p>\n  </div>\n</div>' WHERE template_code = 'VERIFICATION_EMAIL';

-- 为管理员关闭工作流启动的邮件通知
INSERT INTO notification_preferences (user_id, notification_type, channel, enabled, do_not_disturb, created_at, updated_at)
SELECT u.id, 'workflow', 'EMAIL', 0, 0, NOW(), NOW()
FROM users u JOIN roles r ON u.role_id = r.id WHERE r.name = 'ADMIN'
ON DUPLICATE KEY UPDATE enabled = 0, updated_at = NOW();
